// ============================================
// CONFIGURATION - Edit these values
// ============================================
const REPORT_ENGINE_URL = 'http://report-engine-api:8000';

// Template ID from Report Engine
// Get from: http://YOUR_SERVER:8447 → Templates → Edit → URL has template ID
const TEMPLATE_ID = 'REPLACE_WITH_TEMPLATE_ID';

// Period: 24h, 7d, 30d, 90d
const PERIOD = '24h';

// Email settings
const REPORT_EMAIL = 'naveen@codesecure.in';
const EMAIL_SUBJECT = 'Daily Security Report - ' + new Date().toLocaleDateString('en-IN');
const CLIENT_NAME = 'Codesecure Solutions';

return [{
  json: {
    report_engine_url: REPORT_ENGINE_URL,
    template_id: TEMPLATE_ID,
    period: PERIOD,
    report_email: REPORT_EMAIL,
    email_subject: EMAIL_SUBJECT,
    client_name: CLIENT_NAME
  }
}];
